package com.example.shareintenthandler

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity

class ShareReceiverActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_receiver)

        handleIncomingShareIntent(intent)
    }

    private fun handleIncomingShareIntent(intent: Intent?) {
        if (intent == null) return

        val action = intent.action
        val type = intent.type

        if (Intent.ACTION_SEND == action && type != null) {
            when {
                type.startsWith("text/") -> handleText(intent)
                type.startsWith("image/") -> handleImage(intent)
            }
        } else if (Intent.ACTION_SEND_MULTIPLE == action && type != null) {
            if (type.startsWith("image/")) {
                handleMultipleImages(intent)
            }
        }
    }

    private fun handleText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        if (sharedText != null && sharedText.startsWith("http")) {
            // Process the URL
            Toast.makeText(this, "Received URL: $sharedText", Toast.LENGTH_SHORT).show()
        } else {
            Toast.makeText(this, "Invalid or no URL shared", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleImage(intent: Intent) {
        val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
        if (imageUri != null) {
            // Process the image
            Toast.makeText(this, "Received Image: $imageUri", Toast.LENGTH_SHORT).show()
        } else {
            Toast.makeText(this, "No image shared", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handleMultipleImages(intent: Intent) {
        val imageUris: ArrayList<Uri>? = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        if (imageUris != null && imageUris.isNotEmpty()) {
            // Process the images
            Toast.makeText(this, "Received ${imageUris.size} images", Toast.LENGTH_SHORT).show()
        } else {
            Toast.makeText(this, "No images shared", Toast.LENGTH_SHORT).show()
        }
    }
}